<?php $documents = $documents ?? []; $search = $search ?? ''; $status = $status ?? ''; ?>
<div class="page-header"><h1>Export Documentation Center</h1></div>
<div class="card mb-3"><div class="card-body"><form method="get" action="/export-documents" class="row g-3"><div class="col-md-7"><label class="form-label">Search</label><input name="search" class="form-control" value="<?= escapeHtml($search) ?>" placeholder="Document number, buyer or type"></div><div class="col-md-3"><label class="form-label">Status</label><input name="status" class="form-control" value="<?= escapeHtml($status) ?>" placeholder="Status code"></div><div class="col-md-2 d-flex align-items-end"><button class="btn btn-primary w-100">Search</button></div></form></div></div>
<div class="card"><div class="card-body"><div class="table-responsive"><table class="table table-striped datatable"><thead><tr><th>Document No</th><th>Type</th><th>Buyer</th><th>Date</th><th>Status</th><th>Files</th><th>Action</th></tr></thead><tbody><?php foreach ($documents as $document): ?><tr><td><?= escapeHtml($document['document_number']) ?></td><td><?= escapeHtml($document['document_type'] ?? '') ?></td><td><?= escapeHtml($document['buyer_name'] ?? '') ?></td><td><?= escapeHtml($document['document_date']) ?></td><td><?= statusBadge((int) $document['status']) ?></td><td><?= (int) $document['attachment_count'] ?></td><td><a href="/export-documents/<?= (int) $document['id'] ?>" class="btn btn-sm btn-outline-primary">Open Vault</a></td></tr><?php endforeach; ?></tbody></table></div></div></div>